/* adc_hal.h - ADC Hardware Abstraction Layer */
#ifndef ADC_HAL_H
#define ADC_HAL_H

#include <stdint.h>

typedef enum {
    ADC_RES_8BIT  = 8,
    ADC_RES_10BIT = 10,
    ADC_RES_12BIT = 12,
    ADC_RES_16BIT = 16
} adc_resolution_t;

typedef enum {
    ADC_REF_INTERNAL = 0,
    ADC_REF_VCC      = 1,
    ADC_REF_EXTERNAL = 2
} adc_ref_t;

/**
 * @brief Read a single ADC sample
 * @param channel     ADC channel index
 * @param resolution  Desired bit resolution
 * @param ref         Voltage reference selection
 * @param out_value   Pointer to store result
 * @return 0 on success, negative error code on failure
 */
int adc_read(uint8_t channel,
             adc_resolution_t resolution,
             adc_ref_t ref,
             uint16_t *out_value);

int adc_calibrate(uint8_t channel);

#endif /* ADC_HAL_H */
